-- =====================================================
-- Captación: Scouting players + reports
-- Run once in Supabase SQL Editor
-- =====================================================

CREATE TABLE IF NOT EXISTS scouting_players (
  id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  full_name     TEXT NOT NULL,
  position_1    TEXT,
  position_2    TEXT,
  birthdate     DATE,
  foot          TEXT,
  team          TEXT,
  assessment    TEXT,
  nationality   TEXT,
  agency        TEXT,
  club_contract TEXT,
  contacto      TEXT,
  categoria     TEXT,
  comentarios   TEXT,
  created_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS scouting_reports (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  player_id   UUID NOT NULL REFERENCES scouting_players(id) ON DELETE CASCADE,
  fecha       TIMESTAMPTZ,
  titulo      TEXT,
  texto       TEXT,
  author_id   UUID,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

ALTER TABLE scouting_players ENABLE ROW LEVEL SECURITY;
ALTER TABLE scouting_reports  ENABLE ROW LEVEL SECURITY;

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='scouting_players' AND policyname='auth_scouting_players') THEN
    CREATE POLICY auth_scouting_players ON scouting_players FOR ALL USING (auth.role() = 'authenticated');
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename='scouting_reports' AND policyname='auth_scouting_reports') THEN
    CREATE POLICY auth_scouting_reports ON scouting_reports FOR ALL USING (auth.role() = 'authenticated');
  END IF;
END $$;

